const data = $input.first().json.body;

const subject = data.subject_line || 'Your Maison Beauté Newsletter';
const preview = data.preview_text || '';
const body = data.body || '';
const cta = data.cta || 'Discover our pre-loved luxury beauty today.';
const newProducts = data.new_products || [];
const recipient = data.recipient || 'carolinanami@gmail.com';

// Embedded product images (base64 — no external dependency)
const PRODUCT_IMAGES = {
  'lancome': {
    name: 'Lancôme Lip Idôle JuicyTreat',
    subtitle: 'No. 90 Berry Bisou · 8.5ml',
    img: 'data:image/webp;base64,',
    badge: 'MAKE-UP'
  },
  'la mer': {
    name: 'La Mer The Treatment Lotion',
    subtitle: '100ml · Miracle Broth™',
    img: 'data:image/webp;base64,',
    badge: 'SKIN-CARE'
  },
  'u beauty': {
    name: 'U Beauty Resurfacing Compound',
    subtitle: '50ml · SIREN Capsule Technology',
    img: 'data:image/webp;base64,',
    badge: 'SKIN-CARE'
  }
};

// Match products to image cards
const productCards = newProducts
  .map(p => {
    const key = Object.keys(PRODUCT_IMAGES).find(k => p.toLowerCase().includes(k));
    return key ? PRODUCT_IMAGES[key] : null;
  })
  .filter(Boolean)
  .slice(0, 3);

// Body paragraphs
const paragraphs = body
  .split(/\n\n+/)
  .filter(p => p.trim())
  .map(p => `<p style="margin:0 0 20px 0;font-size:15px;line-height:1.8;color:#2A1A3E;font-family:Georgia,serif;">${p.trim()}</p>`)
  .join('');

// Product cards HTML — vertical stack for email reliability
const productCardsHTML = productCards.map(p => `
<tr>
  <td style="padding:0 0 16px 0;">
    <table width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #E8E0DC;border-radius:6px;overflow:hidden;background:#FAFAF9;">
      <tr>
        <td width="120" style="padding:0;vertical-align:top;">
          <img src="${p.img}" alt="${p.name}" width="120" height="120" style="display:block;width:120px;height:120px;object-fit:cover;border-radius:6px 0 0 6px;">
        </td>
        <td style="padding:16px 20px;vertical-align:middle;">
          <p style="margin:0 0 4px 0;font-size:9px;color:#C9748F;font-family:Arial,sans-serif;letter-spacing:0.18em;text-transform:uppercase;font-weight:700;">${p.badge}</p>
          <p style="margin:0 0 6px 0;font-size:14px;color:#1A1A2E;font-family:Georgia,serif;line-height:1.3;">${p.name}</p>
          <p style="margin:0;font-size:11px;color:#9B8FA0;font-family:Arial,sans-serif;">${p.subtitle}</p>
        </td>
      </tr>
    </table>
  </td>
</tr>`).join('');

const productSectionHTML = productCards.length > 0 ? `
<tr>
  <td style="background:#FFFFFF;padding:0 48px 8px;">
    <p style="margin:0 0 20px 0;font-size:10px;color:#C9748F;font-family:Arial,sans-serif;letter-spacing:0.2em;text-transform:uppercase;font-weight:700;border-top:1px solid #E8E0DC;padding-top:32px;">✦ &nbsp;Featured This Edit</p>
    <table width="100%" cellpadding="0" cellspacing="0" border="0">
      ${productCardsHTML}
    </table>
  </td>
</tr>` : '';

const month = new Date().toLocaleDateString('en-GB', {month:'long', year:'numeric'});

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>${subject}</title>
</head>
<body style="margin:0;padding:0;background-color:#F0EBE5;">
<div style="display:none;max-height:0;overflow:hidden;">${preview}</div>
<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#F0EBE5;padding:32px 16px;">
<tr><td align="center">
<table width="560" cellpadding="0" cellspacing="0" border="0" style="max-width:560px;width:100%;">

  <!-- Header -->
  <tr>
    <td style="background:#1A1A2E;padding:36px 48px 28px;border-radius:8px 8px 0 0;">
      <p style="margin:0 0 2px 0;font-size:9px;color:#C9748F;letter-spacing:0.28em;text-transform:uppercase;font-family:Arial,sans-serif;">Pre-Loved Luxury Beauty · Berlin</p>
      <h1 style="margin:8px 0 10px;font-size:34px;color:#F2E8D9;font-weight:normal;font-family:Georgia,serif;letter-spacing:0.03em;">Maison Beauté</h1>
      <div style="width:32px;height:1px;background:#C9748F;margin:0 0 14px;"></div>
      <p style="margin:0;font-size:10px;color:#6B6080;font-family:Arial,sans-serif;letter-spacing:0.12em;text-transform:uppercase;">The Edit · ${month}</p>
    </td>
  </tr>

  <!-- Subject banner -->
  <tr>
    <td style="background:#C9748F;padding:18px 48px;">
      <p style="margin:0;font-size:17px;color:#FFFFFF;font-style:italic;font-family:Georgia,serif;line-height:1.35;">${subject}</p>
    </td>
  </tr>

  <!-- Body copy -->
  <tr>
    <td style="background:#FFFFFF;padding:36px 48px 20px;">
      ${paragraphs}
    </td>
  </tr>

  <!-- Product cards -->
  ${productSectionHTML}

  <!-- CTA -->
  <tr>
    <td style="background:#FFFFFF;padding:28px 48px 40px;">
      <table cellpadding="0" cellspacing="0" border="0">
        <tr>
          <td style="background:#1A1A2E;border-radius:3px;">
            <a href="https://www.revouri.de" style="display:inline-block;padding:14px 34px;font-family:Arial,sans-serif;font-size:11px;font-weight:700;color:#F2E8D9;text-decoration:none;letter-spacing:0.14em;text-transform:uppercase;">${cta}</a>
          </td>
        </tr>
      </table>
    </td>
  </tr>

  <!-- Sustainability strip -->
  <tr>
    <td style="background:#F8F5F2;padding:20px 48px;border-left:3px solid #C9A84C;">
      <p style="margin:0;font-size:12px;color:#9B8FA0;font-family:Arial,sans-serif;line-height:1.7;">✦ &nbsp;Every purchase at Maison Beauté extends the life of a luxury product and keeps it out of landfill. Thank you for choosing circular beauty.</p>
    </td>
  </tr>

  <!-- Footer -->
  <tr>
    <td style="background:#1A1A2E;padding:28px 48px;border-radius:0 0 8px 8px;">
      <p style="margin:0 0 4px;font-size:16px;color:#F2E8D9;font-family:Georgia,serif;">Maison Beauté</p>
      <p style="margin:0 0 16px;font-size:11px;color:#9B8FA0;font-family:Arial,sans-serif;">revouri.de · Berlin, Germany</p>
      <p style="margin:0;font-size:10px;color:#4A3A5A;font-family:Arial,sans-serif;border-top:1px solid #2D1B4E;padding-top:14px;">You received this because you subscribed to The Edit. &nbsp;<a href="#" style="color:#C9748F;text-decoration:none;">Unsubscribe</a></p>
    </td>
  </tr>

</table>
</td></tr>
</table>
</body>
</html>`;

return [{ json: { html, subject, recipient, preview } }];
